import type { EventHandler, SyntheticEvent } from 'react';
import { isNonNullable } from './assert';

/**
 * 组合所有传入的事件句柄，并返回一个新的句柄函数。用户句柄要放在靠前的参数里。
 */
export function composeEventHandlers<T extends EventHandler<SyntheticEvent>>(...fns: (T | undefined)[]) {
  return (event: Parameters<T>[0]) => {
    for (const fn of fns) {
      if (isNonNullable(fn)) {
        fn(event);
      }
      // 防御性编程，可能没有 event 或者 event 没有 isDefaultPrevented 方法
      if (event?.isDefaultPrevented?.()) {
        return;
      }
    }
  };
}
